namespace optiling {

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    Conv2dHardSwishReluCustomTilingData tiling;

    const gert::Shape *x_shape = context->GetInputShape(0);   // [N, Cin, H, W]
    const gert::Shape *w_shape = context->GetInputShape(1);   // [Cout, Cin, Kh, Kw]

    if (x_shape->GetDimNum() != 4 || w_shape->GetDimNum() != 4) {
        return ge::GRAPH_FAILED;
    }

    const uint32_t N  = static_cast<uint32_t>(x_shape->GetDim(0));
    const uint32_t Cin = static_cast<uint32_t>(x_shape->GetDim(1));
    const uint32_t H  = static_cast<uint32_t>(x_shape->GetDim(2));
    const uint32_t W  = static_cast<uint32_t>(x_shape->GetDim(3));

    const uint32_t Cout = static_cast<uint32_t>(w_shape->GetDim(0));
    const uint32_t Kh   = static_cast<uint32_t>(w_shape->GetDim(2));
    const uint32_t Kw   = static_cast<uint32_t>(w_shape->GetDim(3));

    // Fixed stride=1, padding=0 to match the given model.
    if (H < Kh || W < Kw) {
        return ge::GRAPH_FAILED;
    }
    const uint32_t Ho = H - Kh + 1;
    const uint32_t Wo = W - Kw + 1;

    const bool hasBias = (context->GetNumInputs() >= 3) && (context->GetInputShape(2)->GetShapeSize() > 0);

    // Tasks = N * Cout * Ho (each task processes one (n, co, ho) row across Wo)
    uint64_t tasks = static_cast<uint64_t>(N) * static_cast<uint64_t>(Cout) * static_cast<uint64_t>(Ho);
    uint32_t blockDim = 24;
    if (tasks < 8) blockDim = static_cast<uint32_t>(tasks > 0 ? tasks : 1);
    if (blockDim < 1) blockDim = 1;
    if (blockDim > 24) blockDim = 24;

    context->SetBlockDim(blockDim);

    tiling.set_n(N);
    tiling.set_cin(Cin);
    tiling.set_cout(Cout);
    tiling.set_h(H);
    tiling.set_w(W);
    tiling.set_kh(Kh);
    tiling.set_kw(Kw);
    tiling.set_ho(Ho);
    tiling.set_wo(Wo);
    tiling.set_blockDim(blockDim);
    tiling.set_hasBias(hasBias ? 1u : 0u);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspaces = context->GetWorkspaceSizes(1);
    workspaces[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

