    int64_t N  = x_shape->GetDim(0);
    int64_t Cin = x_shape->GetDim(1);
    int64_t H  = x_shape->GetDim(2);
    int64_t W  = x_shape->GetDim(3);

    int64_t Cout = w_shape->GetDim(0);
    int64_t Kh   = w_shape->GetDim(2);
    int64_t Kw   = w_shape->GetDim(3);

    if (H < Kh || W < Kw) {
