#include <torch/library.h>
#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

at::Tensor conv2d_hard_swish_relu_impl_npu(const at::Tensor& x,
                                           const at::Tensor& weight,
                                           c10::optional<at::Tensor> bias_opt) {
    at::Tensor y;
    if (bias_opt.has_value()) {
        at::Tensor bias = bias_opt.value();
        y = at::empty({x.size(0), weight.size(0),
                       x.size(2) - weight.size(2) + 1,
                       x.size(3) - weight.size(3) + 1}, x.options());
        EXEC_NPU_CMD(aclnnConv2dHardSwishReluCustom, x, weight, bias, y);
    } else {
        y = at::empty({x.size(0), weight.size(0),
                       x.size(2) - weight.size(2) + 1,
                       x.size(3) - weight.size(3) + 1}, x.options());
        // Pass an undefined tensor for bias; the runtime will ignore it via hasBias flag
        at::Tensor bias_undef;
        EXEC_NPU_CMD(aclnnConv2dHardSwishReluCustom, x, weight, bias_undef, y);
    }
    return y;
}

TORCH_LIBRARY_IMPL(myops, PrivateUse1, m) {
